import React, { useState, useEffect } from 'react';
import { getTrips, getTrucks, getCustomers, getBackloads, verifyTrip, getExportUrl } from '../api';
import { adToBS, formatBSShort } from '../nepaliDate';
import toast from 'react-hot-toast';

const STATUS_COLOR = {
  open:      { bg: '#fff3cd', color: '#856404' },
  completed: { bg: '#d1ecf1', color: '#0c5460' },
  verified:  { bg: '#d4edda', color: '#155724' },
};

export default function AdminTrips({ onEdit }) {
  const [trips, setTrips]         = useState([]);
  const [trucks, setTrucks]       = useState([]);
  const [customers, setCustomers] = useState([]);
  const [backloads, setBackloads] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [filters, setFilters]     = useState({
    truck_id: '', status: '', from_date: '', to_date: '',
    customer_id: '', backload_id: ''
  });

  const load = async () => {
    setLoading(true);
    try {
      // Only pass non-empty filters to backend (backend handles truck_id, status, dates)
      // customer_id and backload_id we filter client-side since backend may not support yet
      const backendFilters = Object.fromEntries(
        Object.entries(filters)
          .filter(([k, v]) => v && ['truck_id','status','from_date','to_date'].includes(k))
      );
      let data = await getTrips(backendFilters);

      // Client-side filter by customer
      if (filters.customer_id) {
        data = data.filter(t => String(t.customer_id) === String(filters.customer_id));
      }
      // Client-side filter by backload (supplier)
      if (filters.backload_id) {
        data = data.filter(t => String(t.backload_id) === String(filters.backload_id));
      }

      setTrips(data);
    } catch {
      toast.error('Failed to load trips');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    getTrucks().then(setTrucks);
    getCustomers().then(setCustomers);
    getBackloads().then(setBackloads);
  }, []);
  useEffect(() => { load(); }, []);

  const handleFilter = e => setFilters(f => ({ ...f, [e.target.name]: e.target.value }));

  const handleVerify = async (id) => {
    try {
      await verifyTrip(id);
      toast.success('Trip verified');
      load();
    } catch { toast.error('Failed to verify'); }
  };

  const clearFilters = () => {
    setFilters({ truck_id: '', status: '', from_date: '', to_date: '', customer_id: '', backload_id: '' });
  };

  const fmt = n => n != null ? `NPR ${Number(n).toLocaleString()}` : '—';

  const activeFilterCount = Object.values(filters).filter(v => v).length;

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div>
          <h2 style={styles.heading}>All Trips</h2>
          <p style={styles.subtext}>{trips.length} trip{trips.length !== 1 ? 's' : ''} shown</p>
        </div>
        <a
          href={getExportUrl(Object.fromEntries(Object.entries(filters).filter(([,v]) => v)))}
          style={styles.exportBtn}
          download
        >
          ⬇ Export Excel
        </a>
      </div>

      {/* ── Filters ── */}
      <div style={styles.filterBox}>
        <div style={styles.filterRow}>
          {/* Truck */}
          <div style={styles.filterGroup}>
            <label style={styles.filterLabel}>Truck</label>
            <select name="truck_id" value={filters.truck_id} onChange={handleFilter} style={styles.filterInput}>
              <option value="">All Trucks</option>
              {trucks.map(t => <option key={t.id} value={t.id}>{t.truck_number} — {t.driver_name || 'No driver'}</option>)}
            </select>
          </div>

          {/* Customer (Destination) */}
          <div style={styles.filterGroup}>
            <label style={styles.filterLabel}>Customer</label>
            <select name="customer_id" value={filters.customer_id} onChange={handleFilter} style={styles.filterInput}>
              <option value="">All Customers</option>
              {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>

          {/* Backload Supplier */}
          <div style={styles.filterGroup}>
            <label style={styles.filterLabel}>Backload Supplier</label>
            <select name="backload_id" value={filters.backload_id} onChange={handleFilter} style={styles.filterInput}>
              <option value="">All Suppliers</option>
              {backloads.map(b => <option key={b.id} value={b.id}>{b.description}</option>)}
            </select>
          </div>

          {/* Status */}
          <div style={styles.filterGroup}>
            <label style={styles.filterLabel}>Status</label>
            <select name="status" value={filters.status} onChange={handleFilter} style={styles.filterInput}>
              <option value="">All</option>
              <option value="open">Open</option>
              <option value="completed">Completed</option>
              <option value="verified">Verified</option>
            </select>
          </div>
        </div>

        <div style={styles.filterRow}>
          {/* Date range */}
          <div style={styles.filterGroup}>
            <label style={styles.filterLabel}>From Date (AD)</label>
            <input type="date" name="from_date" value={filters.from_date} onChange={handleFilter} style={styles.filterInput} />
          </div>
          <div style={styles.filterGroup}>
            <label style={styles.filterLabel}>To Date (AD)</label>
            <input type="date" name="to_date" value={filters.to_date} onChange={handleFilter} style={styles.filterInput} />
          </div>

          <div style={{ display: 'flex', gap: 8, alignItems: 'flex-end', paddingBottom: 2 }}>
            <button onClick={load} style={styles.filterBtn}>
              🔍 Apply
            </button>
            {activeFilterCount > 0 && (
              <button onClick={clearFilters} style={styles.clearBtn}>
                ✕ Clear ({activeFilterCount})
              </button>
            )}
          </div>
        </div>
      </div>

      {/* ── Table ── */}
      {loading ? (
        <p style={{ textAlign: 'center', padding: 40, color: '#888' }}>Loading trips...</p>
      ) : trips.length === 0 ? (
        <p style={{ textAlign: 'center', padding: 40, color: '#888' }}>No trips found.</p>
      ) : (
        <div style={styles.tableWrap}>
          <table style={styles.table}>
            <thead>
              <tr style={styles.thead}>
                {['#','Truck','Driver','Source','Customer','Start (BS)','End (BS)','Days','KM',
                  'Diesel Needed','Diesel Used','Diesel Dev','Diesel Cost',
                  'Fooding','Bhatta','Load/Unload','Total Exp','Freight','Surplus','Backload','Status','Actions']
                  .map(h => <th key={h} style={styles.th}>{h}</th>)}
              </tr>
            </thead>
            <tbody>
              {trips.map((t, i) => {
                const sc = STATUS_COLOR[t.status] || {};
                return (
                  <tr key={t.id} style={{ background: i % 2 === 0 ? '#fff' : '#f7fafd' }}>
                    <td style={styles.td}>{t.id}</td>
                    <td style={styles.td}><b>{t.truck_number}</b></td>
                    <td style={styles.td}>{t.driver_name || '—'}</td>
                    <td style={{ ...styles.td, maxWidth: 120, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }} title={t.source_name}>{t.source_name}</td>
                    <td style={{ ...styles.td, maxWidth: 160, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }} title={t.customer_name}>{t.customer_name}</td>

                    {/* Dates in BS */}
                    <td style={styles.td}>
                      <span title={t.start_date?.slice(0,10)}>
                        {formatBSShort(adToBS(t.start_date?.slice(0,10)))}
                      </span>
                    </td>
                    <td style={styles.td}>
                      <span title={t.end_date?.slice(0,10)}>
                        {t.end_date ? formatBSShort(adToBS(t.end_date.slice(0,10))) : '—'}
                      </span>
                    </td>

                    <td style={styles.td}>{t.num_days ?? '—'}</td>
                    <td style={styles.td}>{t.distance_km ? `${t.distance_km} km` : '—'}</td>

                    {/* Diesel columns */}
                    <td style={styles.td}>{t.diesel_needed ? `${t.diesel_needed} L` : '—'}</td>
                    <td style={styles.td}>{t.diesel_used ? `${t.diesel_used} L` : '—'}</td>
                    <td style={{ ...styles.td, color: t.diesel_deviation < 0 ? 'red' : t.diesel_deviation > 0 ? 'green' : 'inherit', fontWeight: t.diesel_deviation != null ? 600 : 'normal' }}>
                      {t.diesel_deviation != null ? `${t.diesel_deviation} L` : '—'}
                    </td>
                    <td style={styles.td}>{fmt(t.diesel_cost)}</td>

                    <td style={styles.td}>{fmt(t.fooding)}</td>
                    <td style={styles.td}>{fmt(t.trip_bhatta)}</td>
                    <td style={styles.td}>{fmt(t.loading_unloading)}</td>
                    <td style={{ ...styles.td, fontWeight: 'bold' }}>{fmt(t.total_expenses)}</td>
                    <td style={styles.td}>{fmt(t.freight_amount)}</td>
                    <td style={{ ...styles.td, fontWeight: 'bold', color: t.surplus < 0 ? 'red' : 'green' }}>{fmt(t.surplus)}</td>
                    <td style={{ ...styles.td, maxWidth: 120, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }} title={t.backload_description}>
                      {t.backload_description || '—'}
                    </td>
                    <td style={styles.td}>
                      <span style={{ ...styles.badge, background: sc.bg, color: sc.color }}>{t.status}</span>
                    </td>
                    <td style={styles.td}>
                      <div style={{ display: 'flex', gap: 4 }}>
                        <button onClick={() => onEdit(t.id)} style={styles.editBtn}>Edit</button>
                        {t.status !== 'verified' && (
                          <button onClick={() => handleVerify(t.id)} style={styles.verifyBtn}>✓</button>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

